INSERT INTO `wp_posts` VALUES (22,1,'2026-06-23 14:54:01','2026-06-23 14:54:01','<!-- wp:shortcode -->\n[dubez_teacher_upload]\n<!-- /wp:shortcode -->\n\n<!-- wp:shortcode -->\n[dubez_teacher_view_submissions]\n<!-- /wp:shortcode -->','Teacher Portal','','inherit','closed','closed','','12-revision-v1','','','2026-06-23 14:54:01','2026-06-23 14:54:01','',12,'http://dubez-academy.local/?p=22',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (23,1,'2026-06-23 15:08:08','2026-06-23 15:08:08','<!-- wp:shortcode -->\n[dubez_teacher_upload]\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph -->\n<p>function dubez_teacher_view_submissions_shortcode() {<br>if ( ! current_user_can( \'teacher\' ) ) {<br>return \'</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Access restricted to teachers only.\';<br>}</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>global $wpdb;\n$submissions_table = $wpdb-&gt;prefix . \'dubez_submissions\';\n$posts_table       = $wpdb-&gt;prefix . \'posts\';\n$users_table       = $wpdb-&gt;prefix . \'users\';\n$message           = \'\';\n\n// Handle Grade Update\nif ( isset( $_POST&#91;\'dubez_grade_submit\'] ) ) {\n    if ( ! isset( $_POST&#91;\'dubez_grade_nonce\'] ) || ! wp_verify_nonce( $_POST&#91;\'dubez_grade_nonce\'], \'dubez_grade_action\' ) ) {\n        $message = \'&lt;p style=\"color:red;\"&gt;Security check failed.&lt;/p&gt;\';\n    } else {\n        $submission_id = intval( $_POST&#91;\'submission_id\'] );\n        $grade         = sanitize_text_field( $_POST&#91;\'grade_value\'] );\n\n        $updated = $wpdb-&gt;update(\n            $submissions_table,\n            array( \'grade\' =&gt; $grade ),\n            array( \'id\' =&gt; $submission_id ),\n            array( \'%s\' ),\n            array( \'%d\' )\n        );\n\n        if ( false !== $updated ) {\n            $message = \'&lt;p style=\"color:green;\"&gt;Grade updated successfully!&lt;/p&gt;\';\n        }\n    }\n}\n\n// Fetch data using joins including ID and Grade\n$results = $wpdb-&gt;get_results( \"\n    SELECT \n        s.id,\n        s.submission_text, \n        s.submission_date, \n        s.grade,\n        p.post_title as assignment_title, \n        u.display_name as student_name\n    FROM $submissions_table s\n    INNER JOIN $posts_table p ON s.assignment_id = p.ID\n    INNER JOIN $users_table u ON s.student_id = u.ID\n    ORDER BY s.submission_date DESC\n\" );\n\nob_start();\n?&gt;\n&lt;style&gt;\n    .dubez-submissions-table { width: 100%; border-collapse: collapse; margin-top: 20px; font-family: sans-serif; }\n    .dubez-submissions-table th, .dubez-submissions-table td { border: 1px solid #ddd; padding: 12px; text-align: left; }\n    .dubez-submissions-table th { background-color: #003366; color: white; }\n    .dubez-submissions-table tr:nth-child(even) { background-color: #f9f9f9; }\n    .submission-content { white-space: pre-wrap; font-size: 0.9em; color: #444; margin-bottom: 10px; }\n    .grade-form { display: flex; gap: 5px; }\n    .grade-input { width: 80px; padding: 5px; }\n    .grade-btn { background: #003366; color: #fff; border: none; padding: 5px 10px; cursor: pointer; border-radius: 3px; }\n&lt;/style&gt;\n\n&lt;div class=\"dubez-admin-view\"&gt;\n    &lt;h2&gt;Student Submissions &amp; Grading&lt;/h2&gt;\n    &lt;?php echo $message; ?&gt;\n\n    &lt;?php if ( $results ) : ?&gt;\n        &lt;table class=\"dubez-submissions-table\"&gt;\n            &lt;thead&gt;\n                &lt;tr&gt;\n                    &lt;th&gt;Assignment / Student&lt;/th&gt;\n                    &lt;th&gt;Submission Text&lt;/th&gt;\n                    &lt;th&gt;Date&lt;/th&gt;\n                    &lt;th&gt;Action / Grade&lt;/th&gt;\n                &lt;/tr&gt;\n            &lt;/thead&gt;\n            &lt;tbody&gt;\n                &lt;?php foreach ( $results as $row ) : ?&gt;\n                    &lt;tr&gt;\n                        &lt;td&gt;\n                            &lt;strong&gt;&lt;?php echo esc_html( $row-&gt;assignment_title ); ?&gt;&lt;/strong&gt;&lt;br&gt;\n                            &lt;small&gt;By: &lt;?php echo esc_html( $row-&gt;student_name ); ?&gt;&lt;/small&gt;\n                        &lt;/td&gt;\n                        &lt;td&gt;\n                            &lt;div class=\"submission-content\"&gt;\n                                &lt;?php echo wp_kses_post( $row-&gt;submission_text ); ?&gt;\n                            &lt;/div&gt;\n                        &lt;/td&gt;\n                        &lt;td&gt;&lt;small&gt;&lt;?php echo esc_html( date_i18n( get_option( \'date_format\' ), strtotime( $row-&gt;submission_date ) ) ); ?&gt;&lt;/small&gt;&lt;/td&gt;\n                        &lt;td&gt;\n                            &lt;form method=\"post\" class=\"grade-form\"&gt;\n                                &lt;?php wp_nonce_field( \'dubez_grade_action\', \'dubez_grade_nonce\' ); ?&gt;\n                                &lt;input type=\"hidden\" name=\"submission_id\" value=\"&lt;?php echo esc_attr( $row-&gt;id ); ?&gt;\"&gt;\n                                &lt;input type=\"text\" name=\"grade_value\" class=\"grade-input\" \n                                       placeholder=\"Grade\" value=\"&lt;?php echo esc_attr( $row-&gt;grade ); ?&gt;\"&gt;\n                                &lt;button type=\"submit\" name=\"dubez_grade_submit\" class=\"grade-btn\"&gt;Save&lt;/button&gt;\n                            &lt;/form&gt;\n                            &lt;?php if ( ! empty( $row-&gt;grade ) ) : ?&gt;\n                                &lt;p&gt;&lt;small&gt;Current Grade: &lt;strong&gt;&lt;?php echo esc_html( $row-&gt;grade ); ?&gt;&lt;/strong&gt;&lt;/small&gt;&lt;/p&gt;\n                            &lt;?php endif; ?&gt;\n                        &lt;/td&gt;\n                    &lt;/tr&gt;\n                &lt;?php endforeach; ?&gt;\n            &lt;/tbody&gt;\n        &lt;/table&gt;\n    &lt;?php else : ?&gt;\n        &lt;p&gt;No submissions found.&lt;/p&gt;\n    &lt;?php endif; ?&gt;\n&lt;/div&gt;\n&lt;?php\nreturn ob_get_clean();</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:paragraph -->\n<p>}<br>add_shortcode( \'dubez_teacher_view_submissions\', \'dubez_teacher_view_submissions_shortcode\' );</p>\n<!-- /wp:paragraph -->','Teacher Portal','','inherit','closed','closed','','12-revision-v1','','','2026-06-23 15:08:08','2026-06-23 15:08:08','',12,'http://dubez-academy.local/?p=23',0,'revision','',0);
